// Validate required input fields
const body = $input.first().json.body || $input.first().json;

const required = ['job_title', 'department', 'employment_type', 'seniority_level', 'location_type', 'description_source'];
const missing = required.filter(f => !body[f] || String(body[f]).trim() === '');

if (missing.length > 0) {
  return [{ json: { error: true, message: `Missing required fields: ${missing.join(', ')}`, status: 400 } }];
}

const validEmploymentTypes = ['Full-time', 'Part-time', 'Contract', 'Internship', 'Temporary'];
if (!validEmploymentTypes.includes(body.employment_type)) {
  return [{ json: { error: true, message: `Invalid employment_type. Must be one of: ${validEmploymentTypes.join(', ')}`, status: 400 } }];
}

const validSeniority = ['Junior', 'Mid-level', 'Senior', 'Lead', 'Manager', 'Director', 'VP', 'C-level'];
if (!validSeniority.includes(body.seniority_level)) {
  return [{ json: { error: true, message: `Invalid seniority_level. Must be one of: ${validSeniority.join(', ')}`, status: 400 } }];
}

const validLocation = ['On-site', 'Remote', 'Hybrid'];
if (!validLocation.includes(body.location_type)) {
  return [{ json: { error: true, message: `Invalid location_type. Must be one of: ${validLocation.join(', ')}`, status: 400 } }];
}

const validSources = ['ai_generate', 'manual', 'file_upload'];
if (!validSources.includes(body.description_source)) {
  return [{ json: { error: true, message: `Invalid description_source. Must be one of: ${validSources.join(', ')}`, status: 400 } }];
}

// For manual: require job_description
if (body.description_source === 'manual' && (!body.job_description || String(body.job_description).trim().length < 20)) {
  return [{ json: { error: true, message: 'Manual description must be at least 20 characters', status: 400 } }];
}

return [{ json: { ...body, error: false } }];

