// Assemble a Markdown JD from the JSON Ollama returned (format:'json' guarantees clean JSON)
const input = $('Create - Route by Source').first().json;
const ollamaResponse = $input.first().json;
const NL = String.fromCharCode(10);

function parseJson(text){
  if(!text) return null;
  text = text.replace(/^```(?:json)?\s*/i,'').replace(/\s*```\s*$/i,'').trim();
  try { return JSON.parse(text); } catch(e){}
  const a=text.indexOf('{'), b=text.lastIndexOf('}');
  if(a>=0 && b>a){ try { return JSON.parse(text.slice(a,b+1)); } catch(e){} }
  return null;
}

const raw = ollamaResponse.candidates?.[0]?.content?.parts?.[0]?.text || ollamaResponse.text || '';
const j = parseJson(raw);

function bullets(arr){ return (Array.isArray(arr)?arr:[]).filter(Boolean).map(s=>'- '+String(s).trim()).join(NL); }

let jobDescription = '';
if (j && (j.about || j.responsibilities)) {
  const parts = [];
  parts.push('## About the Role'); parts.push(String(j.about||'').trim());
  parts.push(''); parts.push('## Key Responsibilities'); parts.push(bullets(j.responsibilities));
  parts.push(''); parts.push('## Requirements'); parts.push(bullets(j.requirements));
  if ((j.niceToHave||[]).length){ parts.push(''); parts.push('## Nice to Have'); parts.push(bullets(j.niceToHave)); }
  if ((j.offer||[]).length){ parts.push(''); parts.push('## What We Offer'); parts.push(bullets(j.offer)); }
  jobDescription = parts.join(NL).trim();
}

if (!jobDescription || jobDescription.length < 50) {
  const fb = ['## '+input.job_title, '', '### About the Role', 'We are looking for a '+input.seniority_level+' '+input.job_title+' to join our '+input.department+' team at Diyar United Company.', '', '### Key Responsibilities', '- Define and execute responsibilities aligned with the '+input.job_title+' role', '- Collaborate with cross-functional teams', '- Drive initiatives within '+input.department, '', '### Requirements', '- Relevant experience for a '+input.seniority_level+' position', '- Strong communication and collaboration skills', '', '---', '*Auto-generated template — AI generation was unavailable. Please review and customize.*'].join(NL);
  return [{ json: { ...input, job_description: fb, description_source_type: 'ai_generated', ai_fallback: true } }];
}

return [{ json: { ...input, job_description: jobDescription, description_source_type: 'ai_generated', ai_fallback: false } }];

// Manual paste path — pass through with validation
const input = $('Create - Route by Source').first().json;
const description = input.job_description || '';

if (!description || description.trim().length < 20) {
  return [{ json: { error: true, message: 'Job description must be at least 20 characters', status: 400 } }];
}

return [{ json: { ...input, job_description: description.trim(), description_source_type: 'manual' } }];

// File upload path — extract text from uploaded content
const input = $('Create - Route by Source').first().json;

const fileContent = input.file_content || input.job_description || '';
const fileName = input.file_name || 'unknown';

// Validate file extension
const ext = fileName.toLowerCase().split('.').pop();
const validExtensions = ['pdf', 'docx', 'txt'];

if (!validExtensions.includes(ext)) {
  return [{ json: { error: true, message: `Invalid file type '.${ext}'. Accepted: PDF, DOCX, TXT`, status: 400 } }];
}

if (!fileContent || fileContent.trim().length < 20) {
  return [{ json: { error: true, message: 'File content is empty or too short. Could not extract text from the uploaded file.', status: 400 } }];
}

return [{ json: { ...input, job_description: fileContent.trim(), description_source_type: 'file_upload', uploaded_file_name: fileName } }];

// Merge point — check for errors from any path, then prepare DB insert
const item = $input.first().json;

if (item.error) {
  return [{ json: item }];
}

// Final validation before DB write
if (!item.job_description || item.job_description.trim().length < 10) {
  return [{ json: { error: true, message: 'Job description is empty after processing', status: 400 } }];
}

return [{ json: {
  error: false,
  job_title: item.job_title,
  department: item.department,
  employment_type: item.employment_type,
  seniority_level: item.seniority_level,
  location_type: item.location_type,
  reporting_to: item.reporting_to || null,
  description_source_type: item.description_source_type,
  job_description: item.job_description,
  uploaded_file_name: item.uploaded_file_name || null,
  status: item.status || 'open',
  is_active: item.is_active !== undefined ? item.is_active : true,
  ai_fallback: item.ai_fallback || false
} }];

// Parse optional query parameters for filtering
const query = $input.first().json.query || {};

let whereClauses = [];
let params = [];
let paramIndex = 1;

if (query.is_active !== undefined) {
  whereClauses.push(`is_active = $${paramIndex}`);
  params.push(query.is_active === 'true');
  paramIndex++;
}

if (query.status) {
  whereClauses.push(`status = $${paramIndex}`);
  params.push(query.status);
  paramIndex++;
}

if (query.department) {
  whereClauses.push(`department ILIKE $${paramIndex}`);
  params.push(`%${query.department}%`);
  paramIndex++;
}

const whereSQL = whereClauses.length > 0 ? 'WHERE ' + whereClauses.join(' AND ') : '';
const limit = Math.min(parseInt(query.limit) || 50, 100);
const offset = Math.max(parseInt(query.offset) || 0, 0);

return [{ json: {
  query: `SELECT id, job_title, department, employment_type, seniority_level, location_type, reporting_to, description_source_type, job_description, status, is_active, created_at, updated_at FROM job_openings ${whereSQL} ORDER BY created_at DESC LIMIT ${limit} OFFSET ${offset}`,
  countQuery: `SELECT COUNT(*) as total FROM job_openings ${whereSQL}`,
  params: params
} }];

// Extract and validate the ID from query parameter
const query = $input.first().json.query || {};
const id = parseInt(query.id);

if (!id || isNaN(id) || id < 1) {
  return [{ json: { error: true, message: 'Invalid or missing job opening ID. Use ?id=1', status: 400 } }];
}

return [{ json: { id: id, error: false, sql: 'SELECT * FROM job_openings WHERE id = ' + id } }];

const allItems = $input.all();
const results = allItems.map(i => i.json);
const firstItem = results[0] || {};

if (!firstItem.id) {
  return [{ json: { found: false } }];
}

return [{ json: { found: true, data: firstItem } }];

const query = $input.first().json.query || {};
const body = $input.first().json.body || $input.first().json;
const id = parseInt(query.id || body.id);

if (!id || isNaN(id) || id < 1) {
  return [{ json: { error: true, message: 'Invalid or missing job opening ID. Use ?id=1', status: 400 } }];
}

return [{ json: { id: id, error: false, sql: `UPDATE job_openings SET is_active = NOT is_active, status = CASE WHEN NOT is_active THEN 'open' ELSE 'closed' END WHERE id = ${id} RETURNING *` } }];

const results = $input.all().map(i => i.json);

if (!results || results.length === 0 || !results[0].id) {
  return [{ json: { found: false } }];
}

return [{ json: { found: true, data: results[0] } }];

const body = $input.first().json.body || $input.first().json;
const id = parseInt(body.id);
if (!id || isNaN(id) || id < 1) {
  return [{ json: { error: true, message: 'Missing or invalid job ID', status: 400 } }];
}
const fields = [];
const allowed = ['job_title', 'department', 'employment_type', 'seniority_level', 'location_type', 'reporting_to', 'job_description'];
for (const key of allowed) {
  if (body[key] !== undefined) {
    fields.push(key + " = '" + String(body[key]).replace(/'/g, "''") + "'");
  }
}
if (fields.length === 0) {
  return [{ json: { error: true, message: 'No fields to update', status: 400 } }];
}
const sql = 'UPDATE job_openings SET ' + fields.join(', ') + ', updated_at = NOW() WHERE id = ' + id + ' RETURNING *';
return [{ json: { error: false, sql } }];

const orig = $('Create - Route by Source').item.json;
const sysText = 'You are an expert HR copywriter. Write compelling, professional job descriptions. Respond ONLY with valid JSON matching the requested schema—no preamble, no markdown.';
const userText = `Generate a job description for the position below at Diyar United Company. Return ONLY a JSON object (no other text) with these exact keys:
{"about": "2-3 sentence paragraph about the role", "responsibilities": ["5 to 7 specific bullet strings"], "requirements": ["5 to 7 specific bullet strings"], "niceToHave": ["3 to 4 bullet strings"], "offer": ["3 to 4 bullet strings"]}
Use the real company name "Diyar United Company" where relevant; never use placeholders.

Position:
- Job Title: ${orig.job_title}
- Department: ${orig.department}
- Employment Type: ${orig.employment_type}
- Seniority Level: ${orig.seniority_level}
- Location: ${orig.location_type}${orig.reporting_to ? '\n- Reporting To: ' + orig.reporting_to : ''}${orig.ai_context ? '\n- Required skills/keywords: ' + orig.ai_context : ''}`;
return [{ json: { ...orig, requestBody: JSON.stringify({ model: 'qwen3:4b', prompt: sysText + '

' + userText, stream: false, format: 'json', options: { temperature: 0.2, num_predict: 2048 } }) } }];

const r = $json;
// qwen3 puts response in thinking field when in thinking mode; try all locations
const text = r.response || r.thinking || r.message?.content || '';
return [{ json: { candidates: [{ content: { parts: [{ text }] } }], _source: r.error ? 'ollama_failed' : 'ollama', _model: r.model } }];
